+            // (number of distinct colors in its neighborhood)
+            let mut ordered = Vec::with_capacity(n);
+            let mut colored: HashMap<&str, usize> = HashMap::new();
+            let all_nodes: Vec<&str> = nodes.clone();
+
+            for _ in 0..n {
+                let best = all_nodes
