+                    .filter(|nd| !colored.contains_key(*nd))
+                    .max_by(|a, b| {
+                        let sat_a = graph
+                            .neighbors(a)
+                            .map_or(0, |nbrs| {
+                                nbrs.iter()
+                                    .filter_map(|nb| colored.get(nb))
+                                    .collect::<HashSet<_>>()
+                                    .len()
+                            });
+                        let sat_b = graph
