+                                nbrs.iter()
+                                    .filter_map(|nb| colored.get(nb))
+                                    .collect::<HashSet<_>>()
+                                    .len()
+                            });
+                        sat_a
+                            .cmp(&sat_b)
+                            .then_with(|| graph.degree(b).cmp(&graph.degree(a)))
+                            .then_with(|| a.cmp(b))
+                    })
+                    .copied();
